var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"아르카데나 제국. 왕성.","JPN":"アルカデナ帝国。王城。","ENG":"Royal Palace, The Empire of Arcadena.","TWN":"艾爾卡特納帝國 皇宮","SCN":"阿尔卡德纳帝国， 皇宫内","DEU":"Royal Palace, The Empire of Arcadena.","FRA":"Royal Palace, The Empire of Arcadena."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"구원기사단. <color=#ffd34c>기사단 회의</color> 현장.","JPN":"救世騎士団。<color=#ffd34c>騎士団会議</color>の場。","ENG":"Knights of Redemption. <color=#ffd34c>Knights Council Assembly</color>.","TWN":"救贖騎士團 <color=#ffd34c>騎士團會議</color>現場","SCN":"救赎骑士团，<color=#ffd34c>骑士团会议</color>现场","DEU":"Knights of Redemption. <color=#ffd34c>Knights Council Assembly</color>.","FRA":"Knights of Redemption. <color=#ffd34c>Knights Council Assembly</color>."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"북부 대륙에서 이룬 성과는 이상입니다. 전하.","JPN":"北部の大陸で成し遂げた成果は以上です。殿下。","ENG":"And that is what we've achieved in the northern continent, Your Highness.","TWN":"以上為北方大陸取得的成果，殿下。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"조금 이른 감은 있지만 승기가 기운 듯합니다. ","JPN":"少し早くはありますが、勝機を掴んだのではないかと。","ENG":"It may be a little bit early, but it seems that we are in a favorable position.","TWN":"雖然要下定論還有點早，但似乎是十拿九穩。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적군의 기세가 잦아들었으니, 당분간은 여유가 있을 것 같군요.","JPN":"敵軍の勢いが弱まりましたので、しばらくは余裕がありそうです。","ENG":"We should be able to rest easy for a while, as the enemies have lost their spirits.","TWN":"趁現在敵軍士氣潰散，我們應該可以暫時喘口氣。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"과연 알렌 경이야. 제국 기사단장직에 어울리는 나무랄 데 없는 지휘였네.","JPN":"さすがはバーミンガム卿。帝国の騎士団長に相応しい、申し分のない指揮だった。","ENG":"Well done, Sir Allen. An impeccable display of commanding skills that fits the position of the Empire's Knight Captain.","TWN":"不愧是艾倫卿，名符其實的帝國騎士團團長，調兵遣將高手。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"과찬이시군요. 아군 쪽 피해까지 고려한다면 완승이라고 볼 수는 없습니다.","JPN":"身に余るお言葉です。味方の被害まで考えると、圧勝とは言えません。","ENG":"I am not worthy of that praise. We have not achieved a complete victory, considering the amount of damage that we suffered.","TWN":"殿下過譽了，考慮到我方受到的損失，這場仗不能算是大獲全勝。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>몬테</color>의 건이나, 아직 해결해야 할 문제는 많습니다.","JPN":"<color=#ffd34c>モンテ</color>の件など、まだ解決すべき問題は多く残っています。","ENG":"There are plenty of remaining issues, including the one in <color=#ffd34c>Monte</color>.","TWN":"無論是<color=#ffd34c>蒙特</color>的事，或是其他尚有許多待解決的問題。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나무를 보지 못하는데 어찌 숲을 볼 수 있겠나. 당장은 눈앞의 승리에 기뻐하도록 하지.","JPN":"木を見て森を見ずとは言うが、時には小さなことに気を配ることも必要か。","ENG":"How does one see the forest if one cannot see the trees?","TWN":"若無法享受當下的甜美果實，又怎麼會期待之後的豐收呢？應該享受在當下的勝利才對。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공. 서쪽 변방의 전황은 어떤가?","JPN":"マルチネス卿。西の辺境の戦況はどうだ？","ENG":"Marquise Martinez. What is the outlook on the western border areas?","TWN":"馬汀尼茲侯爵，西方邊境的戰況如何？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"명령하신 대로 반란군 간부를 매수했습니다.","JPN":"ご命令のとおり、反乱軍の幹部を買収しました。","ENG":"We bribed an officer in the rebel forces, as per your order.","TWN":"已經照殿下的吩咐，收買了叛軍的幹部。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"애초 권력욕에 휩싸여 뭉친 오합지졸들이었으니, 군세가 와해되는 건 시간문제일 겁니다.","JPN":"そもそも権力欲に溺れて集まった烏合の衆なので、軍勢が崩れるのは時間の問題でしょう。","ENG":"They were a disorderly group of power-hungry fools, so it is only a matter of time before their troops fall apart.","TWN":"他們不過是一群權欲薰心的烏合之眾，勢力瓦解是遲早的事。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"제 쪽도 별다른 이상은 없었습니다. 전하.","JPN":"僕の方も別に異常はありませんでした。殿下。","ENG":"There was nothing special on my side either, Your Highness.","TWN":"我這裡也沒什麼異狀，殿下。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"잇따른 승전보가 기운을 북돋아 준 것 같아요. 이전보다 사람들의 표정이 많이 좋아졌어요.","JPN":"勝利の知らせが続いたのが彼らを元気づけたようです。以前より人々の表情がだいぶ明るくなりました。","ENG":"The continued news of victory must have lifted the people's spirits. They look a lot brighter than before.","TWN":"接二連三的捷報，也使得民心大振，百姓的臉上都恢復了笑容。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아 쪽은 어때?","JPN":"ルクレシアの方はどう？","ENG":"What about you, Lucrecia?","TWN":"露可蕾西亞那邊呢？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아?","JPN":"ルクレシア？","ENG":"Lucrecia?","TWN":"露可蕾西亞？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 쪽도 별다른 문제는 없었습니다.","JPN":"私の方も、特に問題はありませんでした。","ENG":"I have nothing special to report either, Your Highness.","TWN":"我這邊也沒什麼特殊狀況。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"회의에 집중하지 못하는 건 괘씸하다만. 성녀는 그런 얼굴로 잘도 거짓말을 하는군.","JPN":"会議に集中できないのもけしからんが。そのような顔をしておきながらよくも嘘がつけたものだ、聖女よ。","ENG":"How deplorable of you to be distracted during the council assembly. Are you aware that your face tells a different story?","TWN":"我最討厭有人開會不認真，而且你的表情就寫著有事。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"고하라, 루크레시아. 마을 쪽에 무언가 이상이 있었던 건가?","JPN":"言え、ルクレシア。巡回中、異常でもあったか？","ENG":"Speak, Lucrecia. Was there a problem in the village?","TWN":"說吧，露可蕾西亞，村子那邊是發生什麼事嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건...","JPN":"それは……","ENG":"Well...","TWN":"那個…"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"무도회에서 춤을 춘 남녀는 부부가 된다는 징크스가 있대요!","JPN":"舞踏会で一緒に踊った男女は、夫婦になるっていう噂があるらしいですよ！","ENG":"I heard that whoever dances together at the ball will later become husband and wife!","TWN":"聽說有個魔咒，就是在舞會上共舞的男女會成為夫妻！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"저도 이번에 좋아하는 애한테 용기내서 권유해보려고요.","JPN":"私も今度勇気を出して、好きな子を誘ってみるつもりです。","ENG":"I'm going to muster up some courage to ask my crush.","TWN":"所以我這次要找喜歡的男生跳舞。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님은 어떻게 하실 건가요?","JPN":"聖女様はどうしますか？","ENG":"What about you, Your Holiness?","TWN":"聖女呢？你打算邀請誰？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};